// PressPilot Factory v2 - Transform Input
// Maps frontend form data to AI content generator format

const input = items[0].json;

const categoryMap = {
  'Restaurant / Food Service': 'restaurant',
  'Real Estate / Architecture': 'realestate',
  'Tech / SaaS': 'startup',
  'Health / Wellness': 'fitness',
  'Creative Agency': 'agency',
  'E-commerce': 'ecommerce',
  'Personal Portfolio': 'corporate'
};

const businessName = input.business_name || input.businessName || 'My Business';
const tagline = input.tagline || '';
const description = input.description || '';
const businessType = input.industry || input.businessType || 'corporate';
const category = categoryMap[businessType] || 'corporate';
const logo = input.logo_base64 || input.logo || null;

// Colors from input or defaults
const colors = input.colors || {};

const payload = {
  businessName,
  tagline,
  description,
  category,
  colors: {
    primary: colors.primary || '#1e40af',
    secondary: colors.secondary || '#64748b',
    accent: colors.accent || '#f59e0b'
  }
};

if (logo) {
  payload.logo = logo;
}

return [{ json: payload }];

