// Transform AI output into Factory API v2 format

const input = items[0].json;
const prevData = $('Transform Input').first().json;

// Parse AI response - handle both string and object
let aiContent;
if (typeof input.message === 'string') {
  try {
    aiContent = JSON.parse(input.message);
  } catch (e) {
    // Try to extract JSON from markdown code fences
    const match = input.message.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (match) {
      aiContent = JSON.parse(match[1].trim());
    } else {
      aiContent = JSON.parse(input.message.trim());
    }
  }
} else if (input.message?.content) {
  aiContent = typeof input.message.content === 'string'
    ? JSON.parse(input.message.content)
    : input.message.content;
} else {
  aiContent = input;
}

// Build Factory API v2 payload
const payload = {
  // New v2 fields
  selected_patterns: aiContent.selected_patterns || [],
  strings: aiContent.strings || {},
  images: aiContent.images || {},
  brand_colors: aiContent.brand_colors || {
    primary: prevData.colors?.primary || '#1e40af',
    secondary: prevData.colors?.secondary || '#64748b',
    accent: prevData.colors?.accent || '#f59e0b'
  },
  business: aiContent.business || {
    name: prevData.businessName || 'My Business',
    tagline: prevData.tagline || '',
    phone: '(555) 123-4567',
    email: 'hello@example.com',
    address: '123 Main Street'
  },
  // Preserve logo if provided
  logo: prevData.logo || null,
  // Legacy compat fields so REST API validation passes
  theme_slug: (aiContent.business?.name || prevData.businessName || 'my-theme')
    .toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')
};

return [{ json: payload }];
